pub fn parse < T >
(input : & str, file_name : T, user_actions : & mut ModelicaGrammar ,) -> Result
< ParseTree, ParolError > where T : AsRef < Path >
{
    use parol_runtime ::
    {
        parser ::
        { parse_tree_type :: SynTree, parser_types :: SynTreeFlavor }, syntree
        :: Builder,
    }; let mut builder = Builder ::< SynTree, SynTreeFlavor >:: new_with();
    parse_into(input, & mut builder, file_name, user_actions) ?;
    Ok(builder.build() ?)
}#[allow(dead_code)] pub fn parse_into < 't, T : TreeConstruct < 't >>
(input : & 't str, tree_builder : & mut T, file_name : impl AsRef < Path >,
user_actions : & mut ModelicaGrammar ,) -> Result < (), ParolError > where ParolError :
From < T :: Error >
{
    use modelica_grammar_scanner ::ModelicaGrammarScanner; let mut llk_parser = LLKParser ::
    new(275, LOOKAHEAD_AUTOMATA, PRODUCTIONS, TERMINAL_NAMES,
    NON_TERMINALS,); llk_parser.trim_parse_tree();
  let scanner = ModelicaGrammarScanner :: new(); 
// Initialize wrapper
let mut user_actions = ModelicaGrammarAuto :: new(user_actions);
    llk_parser.parse_into(tree_builder, TokenStream ::
    new(input, file_name, scanner.scanner_impl.clone(), &ModelicaGrammarScanner ::
    match_function, MAX_K,).unwrap(), & mut user_actions)
}